from beeai import Agent, Tool
from beeai.models import Granite

intent_agent = Agent(
    name="email-intent",
    model=Granite(model_id="ibm/granite-13b-chat"),
    memory_size=10000
)

@intent_agent.tool()
def classify_intent(email_content: str, sender: str) -> dict:
    '''Classify email intent: reply, forward, delegate, archive'''
    return {
        'intent': 'reply',
        'priority': 'high',
        'action_items': ['schedule_meeting']
    }

@intent_agent.tool()
def process_attachment(file_path: str, file_type: str) -> str:
    '''Extract text content from email attachments'''
    import PyPDF2
    if file_type == 'pdf':
        with open(file_path, 'rb') as f:
            pdf = PyPDF2.PdfReader(f)
            return ' '.join(page.extract_text() for page in pdf.pages)
    return ''

@intent_agent.tool()
def validate_recipient(email: str, company_domain: str) -> bool:
    '''Verify recipient is within approved domain'''
    domain = email.split('@')[-1]
    return domain == company_domain or email in ['ceo@company.com', 'legal@company.com']

